// Analyze ad performance and detect optimization opportunities
const insights = $input.first().json.data || [];

if (insights.length === 0) {
  return { status: 'no_data', message: 'No ad insights available for analysis.' };
}

const analysis = [];
let totalSpend = 0;
let totalImpressions = 0;
let totalClicks = 0;

for (const ad of insights) {
  const spend = parseFloat(ad.spend) || 0;
  const impressions = parseInt(ad.impressions) || 0;
  const clicks = parseInt(ad.clicks) || 0;
  const cpc = parseFloat(ad.cpc) || 0;
  const ctr = parseFloat(ad.ctr) || 0;
  const cpm = parseFloat(ad.cpm) || 0;
  const conversions = parseInt(ad.conversions) || 0;
  const costPerConversion = ad.cost_per_action_type?.[0]?.value || null;

  totalSpend += spend;
  totalImpressions += impressions;
  totalClicks += clicks;

  const issues = [];

  // High CPC alert
  if (cpc > 2.0) {
    issues.push(`High CPC: $${cpc.toFixed(2)} (target < $2.00)`);
  }

  // Low CTR alert
  if (ctr < 1.0 && impressions > 1000) {
    issues.push(`Low CTR: ${ctr.toFixed(2)}% (target > 1%)`);
  }

  // High spend with no conversions
  if (spend > 50 && conversions === 0) {
    issues.push(`High spend ($${spend.toFixed(0)}) with zero conversions`);
  }

  // High CPM
  if (cpm > 20) {
    issues.push(`High CPM: $${cpm.toFixed(2)} (target < $20)`);
  }

  analysis.push({
    ad_id: ad.ad_id,
    ad_name: ad.ad_name || 'Unnamed Ad',
    adset_name: ad.adset_name || 'Unknown',
    campaign_name: ad.campaign_name || 'Unknown',
    spend: spend,
    impressions: impressions,
    clicks: clicks,
    cpc: cpc,
    ctr: ctr,
    cpm: cpm,
    conversions: conversions,
    cost_per_conversion: costPerConversion,
    issues: issues,
    needs_attention: issues.length > 0
  });
}

const avgCpc = totalClicks > 0 ? totalSpend / totalClicks : 0;
const avgCtr = totalImpressions > 0 ? (totalClicks / totalImpressions) * 100 : 0;

return {
  report_period: 'Last 7 days',
  ads_analyzed: insights.length,
  total_spend: Math.round(totalSpend * 100) / 100,
  total_impressions: totalImpressions,
  total_clicks: totalClicks,
  avg_cpc: Math.round(avgCpc * 100) / 100,
  avg_ctr: Math.round(avgCtr * 100) / 100,
  ads_need_attention: analysis.filter(a => a.needs_attention).length,
  ad_details: analysis.filter(a => a.needs_attention),
  client_id: $env.CLIENT_ID || 'unknown'
};

// Build optimization prompt for the LLM router
const data = $input.first().json;
const brandVoice = $env.BRAND_VOICE || 'professional';

let adDetails = '';
for (const ad of data.ad_details) {
  adDetails += `\n- Ad: "${ad.ad_name}" (Campaign: ${ad.campaign_name}, AdSet: ${ad.adset_name})\n`;
  adDetails += `  Spend: $${ad.spend.toFixed(2)} | Impressions: ${ad.impressions} | Clicks: ${ad.clicks} | CPC: $${ad.cpc.toFixed(2)} | CTR: ${ad.ctr.toFixed(2)}%\n`;
  adDetails += `  Issues: ${ad.issues.join('; ')}\n`;
}

const prompt = `You are a Meta Ads optimization expert for ${$env.CLIENT_NAME || 'a client'}. Brand voice: ${brandVoice}.

Ad Performance Report (Last 7 Days):
- Total Spend: $${data.total_spend}
- Total Impressions: ${data.total_impressions}
- Total Clicks: ${data.total_clicks}
- Average CPC: $${data.avg_cpc}
- Average CTR: ${data.avg_ctr}%
- Ads Needing Attention: ${data.ads_need_attention} out of ${data.ads_analyzed}

Problematic Ads:
${adDetails}

Provide 3 actionable, specific optimization recommendations. Consider:
1. Budget reallocation suggestions
2. Creative/targeting improvements
3. Bid strategy adjustments

IMPORTANT: Do NOT suggest changes that would increase spend beyond 20% of current levels. Always include a risk assessment.

Respond in JSON format:
{
  "summary": "Brief overall assessment",
  "recommendations": [
    {
      "ad_id": "ad id",
      "action": "specific action to take",
      "expected_impact": "what improvement to expect",
      "risk_level": "low/medium/high"
    }
  ],
  "budget_adjustments": [
    {
      "ad_id": "target ad",
      "current_daily_budget": 0,
      "suggested_daily_budget": 0,
      "rationale": "why"
    }
  ]
}`;

return {
  task_type: 'analysis',
  user_message: prompt,
  context: `Meta Ads optimization for ad account ${$env.META_AD_ACCOUNT_ID || 'N/A'}. Client: ${$env.CLIENT_ID}.`
};

// Apply only the approved changes flagged by human
// The human-in-the-loop response should come back via webhook with approved actions
const approvalData = $input.first().json;
const approvedActions = approvalData.approved_actions || [];

if (approvedActions.length === 0) {
  return { status: 'no_actions_approved', message: 'No actions were approved by the reviewer.' };
}

return {
  status: 'approved',
  actions_count: approvedActions.length,
  approved_actions: approvedActions,
  applied_at: new Date().toISOString(),
  client_id: $env.CLIENT_ID
};
